var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"내가 지원하고 있는 민간 항공 우주 시설이라네.","JPN":"私が支援している民間空港宇宙施設だ。","ENG":"There's a private aerospace facility that I've been supporting.","TWN":"我有家資助的民用航太設施。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"민간 항공 우주 시설이라고?","JPN":"民間空港宇宙施設だと？","ENG":"A private aerospace facility?","TWN":"民用航太設施？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇네.","JPN":"そうだ。","ENG":"Correct.","TWN":"沒錯。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"관리국의 항공 우주 관제 시설은 지금 적의 공격에 의해서 그 기능이 마비되었거든.","JPN":"管理局の航空宇宙管制施設は今、敵の攻撃によってその機能が麻痺している。","ENG":"You see, the Administration's aerospace control facility is currently down due to the enemy's attack.","TWN":"目前管理局的航太控制設施因為敵方的攻擊都癱瘓了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"보험인 동시에 어느정도는 투자라고 할 수 있지.","JPN":"保険であると同時に、投資だとも言えるだろう。","ENG":"Consider it a combination of insurance and investment.","TWN":"你可以把它當做一種保險，也是一種投資。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그러고보니…….","JPN":"そういえば……","ENG":"Now that I think of it...","TWN":"這麼一想……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그때, 모더레이터가 공격하고 있던 시설도 관제 시설이었어.","JPN":"あの時、モデレーターが攻撃していた施設も管制施設だった。","ENG":"Yeah, the Moderator's target was also a control facility.","TWN":"當時，被仲裁者攻擊的也是控制設施。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"설마 이런 상황을 예측하고……?","JPN":"まさか、こうなることを予測して……？","ENG":"Did it predict that this would happen...?","TWN":"你該不會也預測到了……？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"으음, 왜 그러지? 내 얼굴에 뭐라도 묻었나?","JPN":"うむ、どうした？　私の顔に何かついているかね？","ENG":"Hmm? What's wrong? Is there something on my face?","TWN":"嗯，怎麼了？我臉上有東西嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"역시 당신…….","JPN":"やっぱりあなた……","ENG":"I guess...","TWN":"你果然……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"최고 관리자라는 말은 거짓말이 아닌 것 같네.","JPN":"最高管理者ってのはウソじゃないみたいだな。","ENG":"you weren't lying when you said you were the Supreme Administrator.","TWN":"是最高管理者，看來不是在撒謊。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"내가 왜 거짓말을 하겠나.","JPN":"私が嘘をつく理由がないさ。","ENG":"Now, why would I lie about that?","TWN":"我為什麼要撒謊？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그 잘나 빠진 하이브 컨트롤 뒤에 관리국을 총괄하는 사람이 있다는 소문을 듣긴 했지만.","JPN":"あのド偉いハイブコントロールの後ろに、管理局を総括する人物がいるってウワサは聞いてたけど……","ENG":"I heard rumors about someone in charge of the Administration behind Hive Control,","TWN":"我有聽過你的傳言，聽說在巢穴控制系統背後，有一個人掌管著管理局。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"상상 이상으로 뻔뻔한 녀석이었잖아?","JPN":"思った以上に図々しいやつだな。","ENG":"but that person turns out to be even more shameless than I expected!","TWN":"但你比我想像得臉皮還要厚。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"후후, 그런 이야기 많이 듣는다네.","JPN":"ふふ、よく言われるよ。","ENG":"Haha, I get that a lot.","TWN":"哈哈，我經常聽人這麼說。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"뭐, 당신에게 묻고 싶은 건 많지만, 지금은 그런 게 중요한 게 아니겠지.","JPN":"ま、あなたに聞きたいことは山ほどあるが、今はそれどころじゃないな。","ENG":"Well, I have loads of questions I want to ask, but that's not what's important right now.","TWN":"好吧，我有很多事情想問你，但現在已經不重要了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"좋아, 모두를 구할 수만 있다면 당신이 누구인지는 상관없어.","JPN":"よし、みんなを助けられるなら、あなたの正体は関係ない。","ENG":"All right, I don't care who you are as long as I can save everyone.","TWN":"只要能夠拯救所有人，你是誰並不重要。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"야크샤의 우두머리로서 기꺼이 협력하지.","JPN":"ヤクシャーのリーダーとして、喜んで協力しよう。","ENG":"As the head of Yaksha, I'm willing to cooperate.","TWN":"作為夜叉的領袖，我願意配合。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이해해줘서 고맙군.","JPN":"理解してくれてありがとう。","ENG":"Thank you for understanding.","TWN":"感謝你的理解。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그래서? 내가 뭘 하면 되는데?","JPN":"それで？　アタシは何をすればいい？","ENG":"So? What should I do?","TWN":"所以？我應該做些什麼？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"이건……?","JPN":"これは……？","ENG":"What's this...?","TWN":"這是……？"},"stage":{"bg":"MAINSTREAM_5201010","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네가 탑승하게 될 귀환선 모듈이라네. 소유즈 우주선을 베이스로 개량한 버전이지.","JPN":"君が搭乗することになる帰還船モジュールさ。ソユーズ宇宙船をベースに、改良したバージョンだ。","ENG":"This is the reentry capsule module that you'll be riding in. It's based on the Soyuz spacecraft with some modifications.","TWN":"這是你將要搭乘的回程艙模組。是基於聯盟號宇宙船的改量版本。"},"stage":{"bg":"MAINSTREAM_5201010","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"오늘 발사 예정이었던 발사체를 내가 매입해서 발사를 2시간 지연시켰네.","JPN":"今日発射する予定だった発射体を私が買い入れて、発射を2時間引き延ばした。","ENG":"I bought the launch vehicle that was supposed to launch into space today and delayed it by two hours.","TWN":"我收購了原定於今天發射的火箭，並將發射推遲了兩個小時。"},"stage":{"bg":"MAINSTREAM_5201010","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"지금 관리국과의 통신이 가능하도록 라인을 연결하고 있어.","JPN":"今管理局との通信ができるように、ラインを繋げている。","ENG":"Right now, I'm connecting the lines to enable communication with the Administration.","TWN":"目前我正在連接與管理局的通訊。"},"stage":{"bg":"MAINSTREAM_5201010","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"뭐? 오늘 매입했다고?","JPN":"はあ？　今日買い入れた？","ENG":"What? You bought it today?","TWN":"什麼？你今天收購的？"},"stage":{"bg":"MAINSTREAM_5201010","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"작전을 위해서야. 발사는 예정대로 진행될 걸세.","JPN":"作戦のためだ。発射は予定通りに行われる。","ENG":"It's for the operation. The launch will go as planned today.","TWN":"為了作戰。發射仍會在今天進行。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 공식적으로는 오늘 발사 시험은 실패라고 보도될 거야.","JPN":"だが、公式的には今日の発射試験は失敗したと報道されるはずだ。","ENG":"But officially, today's test will be reported as a failure.","TWN":"不過，官方會將此次發射報導為失敗。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"왜냐하면 대기권을 돌파하면, 적의 공격에 포착되어 우주선이 폭발하게 될 테니까.","JPN":"何故なら、大気圏を突破したタイミングで敵からの攻撃を受け、宇宙船は爆発するだろうからな。","ENG":"Because as soon as it breaks through the atmosphere, it'll be detected by the enemy and explode.","TWN":"因為一旦你突破了大氣層，就會被敵人鎖定，屆時太空船將被炸毀。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"한 일주일 정도는 폭발의 원인이니, 세금 낭비니 이런저런 뉴스가 나돌겠지.","JPN":"一週間ほどは爆発の原因だの、税金の無駄遣いだの、色んなニュースが流される。","ENG":"For about a week, people will discuss how it was a waste of taxpayer money and what caused the explosion.","TWN":"不超過一週，就會出現關於爆炸原因、浪費稅金之類的新聞。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 시간이 지나면, 무인 우주 발사체의 실패 같은 건 아무도 기억하지 않을 테니까.","JPN":"だが時間が過ぎると、無人宇宙発射体の失敗など誰も覚えていないだろう。","ENG":"But after the dust settles, no one will remember a failed unmanned spacecraft.","TWN":"但隨著時間的流逝，沒有人會記得這次的火箭發射。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"정말이지, 지극히 관리국다운 방식이네.","JPN":"まったく、本当に管理局らしいやり方だな。","ENG":"Wow, that really is the way of the Administration to look at things.","TWN":"確實，這種做法很管理局。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그래서 비공식적으로는 어떤데? 내가 뭘 하면 되지?","JPN":"で、非公式的には？　アタシは何をすればいい？","ENG":"So? What about unofficially? What do I have to do?","TWN":"那麼暗地裡呢？我要怎麼做？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"정보오염된 관리국 전략위성의 신호가 잡힌 건 고도 400Km의 저고도.","JPN":"情報汚染された管理局戦略衛星の信号が補足されたのは、400Kmの低い高度だ。","ENG":"The signal of the data-corrupted Administration strategic satellite is caught at a low altitude of 400 km.","TWN":"遭受資訊污染的管理局戰略衛星位於距地400公里的低空。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네는 이 우주선을 타고 거기까지 올라가게 될 거야.","JPN":"君はこの宇宙船に乗ってあそこまで上がることになる。","ENG":"You will ride this shuttle all the way up there.","TWN":"你將乘坐這艘太空船前往那裡。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 다음 적기를 확인하고, 자네의 공간 도약 능력으로 적의 동력원을 파괴하게.","JPN":"その後敵機を確認し、君の空間跳躍能力で敵の動力源を破壊してくれ。","ENG":"Then, you'll use your space jump ability to destroy its power source as soon as you identify the enemy.","TWN":"接著，利用你的空間跳躍能力，找出敵機，摧毀他們的動力源。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"적기의 제거가 확인되는 즉시, 연합 전대는 필하모닉 홀에 다이브를 시도.","JPN":"敵機の除去が確認できた同時に、連合戦隊はフィルハーモニーホールにダイブを開始。","ENG":"Once the reactor has been eliminated, the coalition divisions will immediately dive to Philharmonic Hall.","TWN":"聯合戰隊一旦確認消滅敵機，就會嘗試躍入管弦樂廳。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"동시에 관리국은 우주선을 보내 자네를 구출할 거야.","JPN":"その隙に管理局は宇宙船を送り君を救出するのだ。","ENG":"Meanwhile, the Administration will send a space shuttle to rescue you.","TWN":"與此同時，管理局會派出一艘宇宙船去營救你。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"젠장……!","JPN":"くそ……！","ENG":"Dammit...!","TWN":"該死……！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"듣기만 해도 엄청 어려운 작전이잖아? 그게 정말 가능한 게 맞아?","JPN":"なんだよその高難度な作戦は。それ、本当にできるのか？","ENG":"That sounds like a very complicated operation. Are you sure this will work?","TWN":"這個作戰，光是聽起來就非常困難，你確定真的有可能成功？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이 작전은 공간 도약 능력에 크게 의존하고 있어.","JPN":"この作戦は空間跳躍能力に大いに依存している。","ENG":"The operation relies heavily on your space jump ability.","TWN":"這個作戰能否成功，很大程度上取決於你的空間跳躍能力。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"우주 공간에서 자네의 능력은 특별해. 다른 인원에게는 결코 불가능한 일일세.","JPN":"宇宙空間で君の能力は特別だ。他の人員には決してできないことさ。","ENG":"Your ability in outer space is special. This will never work with anyone else.","TWN":"你的能力在外太空中無人能及。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"뭐, 좋아……!","JPN":"ま、いいよ……！","ENG":"Uh, okay...!","TWN":"呼，那好吧……！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그럼, 까짓 거 한 방에 성공시켜주겠어.","JPN":"一発で成功させてやる。","ENG":"Then, I'll make sure to do it in one go.","TWN":"那麼，就儘量一次成功吧。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"다시는 내 앞에서 아무도 죽게 내버려두지 않겠다고 맹세했으니까.","JPN":"アタシの目の前では二度と、誰も死なせないと誓ったからな。","ENG":"Because I'm not going to allow anyone to die on my watch anymore.","TWN":"我不會再讓任何人死在我的面前。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"묻고 싶은 게 있네. 앨리스 전대장.","JPN":"聞きたいことがある。アリス戦隊長。","ENG":"Commander Alice, I want to ask you something.","TWN":"我有個問題想問你。艾莉絲戰隊長。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네는 무섭지 않나?","JPN":"君は怖くないのか？","ENG":"Aren't you scared?","TWN":"你不害怕嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이 작전에, 자네의 손에 수많은 목숨이 달려 있네.","JPN":"この作戦に、君の手に、多くの命がかかっている。","ENG":"Countless lives are in your hands in this operation.","TWN":"這次作戰，有無數人的生命都掌握在你的手裡。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네가 상상하는 것 이상으로 말이야.","JPN":"君が想像している以上に、だ。","ENG":"Possibly more than you can even imagine.","TWN":"數量多得超乎你的想像。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"뭐, 무섭지 않다면 거짓말이겠지.","JPN":"まあ、怖くないって言ったらウソだけど。","ENG":"Well, I'd be lying if I said I wasn't.","TWN":"唔，說不害怕是假的。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"소방관 시절에도 매번 불 속에 들어가는 건 무서웠으니까.","JPN":"消防士だった頃だって、毎度炎の中に飛び込むのは怖かったからな。","ENG":"But I was also always scared of going into fires when I was a firefighter.","TWN":"在我還是消防員的時候，每次進入火場前我都會害怕。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"나는 그저 내 앞에서 누군가가 죽는 걸 보고 싶지 않을 뿐이야.","JPN":"アタシはただ、自分の目の前で誰かが死ぬところを見たくないだけだ。","ENG":"All I want is for no one to die on my watch.","TWN":"我只是不想看到有人死在我面前。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그리고 이번에 위기에 빠진 건, 그 무엇과도 바꿀 수 없는 소중한 사람들이고.","JPN":"それに今危険な目に遭っているのは、アタシにとってかけがえのない大切な人たちだ。","ENG":"And the people in danger right now are those I would never replace for anything in the world.","TWN":"而這一次，陷入危險的是任何東西都無法替代的，我的重要之人。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그동안 힘든 일도, 즐거운 일도, 슬픈 일도……. 전부 그 녀석들과 함께 해왔어.","JPN":"辛いことも、楽しいことも、悲しいことも……全部あいつらと一緒だった。","ENG":"All the hardships, joys, and sorrow... I experienced it all while being next to them.","TWN":"那段時間，有過困難，有過快樂，有過悲傷……是他們陪我一起度過了那些時光。"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_CAT","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그러니까 이건 세계를 구한다는 거창한 일도, 관리국의 안배대로 행동하는 것도 아니야.","JPN":"だからこれは世界を救うなんて大層な理由でも、管理局の思いどおりに行動するわけでもない。","ENG":"So this isn't about some grandiose plan of saving the world, or acting according to the Administration's plans.","TWN":"所以，不是為了拯救世界，也不是為了管理局。"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_CAT","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"이건 내가 내 의지로 선택한 일이야.","JPN":"これはアタシの意思だ。","ENG":"I'm doing this on my own accord.","TWN":"我的行為是我自己的選擇，我自己的意志。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L42_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"나 자신과 나의 소중한 전대원들을 구하기 위해서.","JPN":"アタシ自身と、大切な戦隊員を救うために。","ENG":"So that I can save my precious division members and myself.","TWN":"為了拯救我自己和重要的戰隊員。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그다지 마음에는 안 들지만. 일단, 감사 인사는 해두어야겠지.","JPN":"気は向かないけど。一応は、感謝するべきなんだろうな。","ENG":"I don't really like it, but I'll say thank you for now.","TWN":"雖然我不喜歡這種話，但我必須要對你說聲謝謝。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그러니까 고마워, 최고 관리자.","JPN":"ありがとう。最高管理者。","ENG":"So, thanks, Supreme Administrator.","TWN":"最高管理者……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"소중한 동료들을 구할 수 있는 기회를 만들어줘서.","JPN":"大事な仲間を助けるチャンスを作ってくれて。","ENG":"For this opportunity to save my comrades.","TWN":"謝謝你給了我拯救同伴的機會。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……알겠네.","JPN":"……わかった。","ENG":"...Very well.","TWN":"……我知道了。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그럼, 기다리고 있겠네. 앨리스 전대장.","JPN":"では、待つとしよう。アリス戦隊長。","ENG":"Then, I'll be waiting, Commander Alice.","TWN":"我等著你回來，艾莉絲戰隊長。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"젠장할! 사람 목숨 구하는데 이것저것 따지면 늦습니다!","JPN":"ああくそ！　人の命を助けるのにそんなこと言ってたら間に合わないんですよ！","ENG":"Dammit! Well, it'll be too late to save them if you keep on nitpicking like that!","TWN":"該死的！再這樣瞻前顧後的，就來不及救人了！"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L4_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"이 방법 말고 1시간 내로 필하모닉 홀로 다이브할 수 있는 다른 방법이 있습니까!","JPN":"じゃあ1時間以内にフィルハーモニーホールにダイブできる方法が他にあるんですか！","ENG":"Then is there another way to dive to Philharmonic Hall within an hour?!","TWN":"除此之外，還有其他可以在1小時躍入管弦樂廳的辦法嗎？！"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그건……!","JPN":"それは……！","ENG":"That’s...!","TWN":"那個……！"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"절 보내주십시오. 힐데 전대장님!","JPN":"アタシを行かせてください。ヒルデ戦隊長！","ENG":"Send me up, Commander Hilde!","TWN":"讓我去吧。希爾德戰隊長！"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"반드시…… 반드시 그 고철 덩어리를 지표면에 처박아버리겠습니다!","JPN":"必ず……必ずあの鉄くずの塊を地面に打ち込んでやります！","ENG":"I promise... to throw that hunk of junk down to the ground!","TWN":"我一定……一定會把那塊廢鐵撞爛！"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그 대신, 한 가지만 약속해주십시오.","JPN":"その代わりに、一つだけ約束してください。","ENG":"In return, promise me this.","TWN":"不過，請答應我一件事。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"필하모닉 홀에 갇힌 우리 전대원들을…… 꼭 구해주시는 겁니다.","JPN":"フィルハーモニーホールに閉じ込められたアタシの戦隊員を……絶対助けてくださいよ。","ENG":"You have to... rescue my division members trapped in Philharmonic Hall.","TWN":"我的戰隊員被困在了管弦樂廳……請一定要救救他們。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"알겠다. 약속하지.","JPN":"わかった。約束しよう。","ENG":"Understood. I give you my word.","TWN":"我知道了。我向你保證。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"그리고 자네도 무사 귀환하길 빌겠다, 앨리스 전대장.","JPN":"そしてお前が無事帰還することを祈る、アリス戦隊長。","ENG":"Then, I hope for your safe return, Commander Alice.","TWN":"也希望你能平安歸來，艾莉絲戰隊長。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"걱정하지 마십시오.","JPN":"心配はご無用です。","ENG":"Don't worry.","TWN":"不用擔心。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"임무를 완수하고 보란 듯이 살아서 돌아올 테니까요.","JPN":"任務を完遂し、胸張って生還してみせますから。","ENG":"I'll complete my mission and return safe and sound.","TWN":"我會順利完成任務，毫髮無傷地活著回來的。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"후우…….","JPN":"ふう……","ENG":"*Sigh*","TWN":"呼……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"내가 요격에 성공한다면, 펜릴 전대는 반드시 우리 전대원들을 구해내겠지.","JPN":"アタシが迎撃に成功すれば、フェンリル戦隊は必ずアタシの戦隊員を助けてくれるはずだ。","ENG":"If I take that ship down, then the Fenrir Division will rescue my members no matter what.","TWN":"如果成功了，芬里爾戰隊就一定能救出我的戰隊員。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"전우들을 믿는 거야. 펜릴 전대는 무적이니까!","JPN":"戦友を信じるんだ。フェンリル戦隊は無敵だから！","ENG":"I trust them. Because the Fenrir Division is invincible!","TWN":"我相信我的戰友。因為芬里爾戰隊是無敵的！"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"반드시 성공해야 해. 성공해서 펜릴에게 길을 열어 주는 거야.","JPN":"必ず成功させなければ。成功してフェンリルに道を開いてやるんだ。","ENG":"I must succeed. And open the way for the Fenrir Division.","TWN":"拜託了。只有成功，才能為芬里爾開闢出一條道路。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"더는 후회 같은 걸 남기지 않도록…….","JPN":"もう二度と、後悔なんかしないように……","ENG":"So that I won't have any regrets...","TWN":"我不會再留下遺憾……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"이번에야말로…… 모두를 구해내고, 웃으면서 녀석들을 맞이하는 거야.","JPN":"今度こそ、みんなを救い出して、笑顔でやつらを迎えるんだ。","ENG":"This time... I'll save them all and greet them all with a smile.","TWN":"這一次……我會拯救所有人，帶著微笑迎接他們歸來。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"전대장님────!!","JPN":"戦隊長────！！","ENG":"COMMANDER!!","TWN":"戰隊長……！！"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"쥐스틴……?","JPN":"ジュスティーヌ……？","ENG":"Justine...?","TWN":"潔絲婷……？"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"하아, 하아, 하아……!!","JPN":"はあ、はあ、はあ……！！","ENG":"*Huff* *Huff* *Huff*","TWN":"哈啊，哈啊，哈啊……！！"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"다행입니다요! 늦지 않았습니다요! 정시 도착입니다요!","JPN":"よかったでやんす！　間に合ったでやんす！　定時到着でやんす！","ENG":"Thank goodness! I wasn't late! Right on time!","TWN":"謝天謝地！不算太晚！準時到達！"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"뭐야, 어쩐 일이야? 본부에 남아 있는 거 아니었어?","JPN":"なんだ、どうした？　本部に残ってたんじゃなかったのか？","ENG":"W-what's going on? Aren't you supposed to stay at the base?","TWN":"什麼，發生什麼事了？你沒留在總部嗎？"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"이걸, 전해드리려고 왔습니다요.","JPN":"これを、渡すために来たでやんす。","ENG":"I came to give you this.","TWN":"我是來給你這個的。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"뒤로 돌아주시는 겁니다요. 슈트에 장착해 드리겠습니다요.","JPN":"背中を見せてほしいでやんす。スーツに装着するでやんす。","ENG":"Could you turn around for me? I'll install it on your suit.","TWN":"你能轉過身去嗎。我把它裝在你的強化服上。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"이건……?","JPN":"これは……？","ENG":"This is...","TWN":"這是……？"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"항상 생각해왔습니다요.","JPN":"いつも思ってたんでやんすよ。","ENG":"I've been thinking.","TWN":"我一直在想。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L48_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"비스트 클로는 어디까지나 라이오넬 전대장님의 고유무장.","JPN":"ビーストクローはあくまでもライオネル戦隊長の固有武装。","ENG":"Beast Claw will always be Commander Lionel's Unique Gear.","TWN":"畢竟，魔獸爪是萊諾戰隊長的專屬裝備。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"그러니까 앨리스 전대장님의 능력과 시너지를 낼 수 있는 장비가 필요하다고.","JPN":"だから、それとは別にアリス戦隊長の能力とシナジーを生み出せる装備が必要だって。","ENG":"So you need equipment that can synergize with your ability, Commander Alice.","TWN":"所以，我們需要一個能夠發揮你的能力的裝備。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"……그럼?","JPN":"……で？","ENG":"...So?","TWN":"……然後？"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"그동안 추적해왔던 적의 동력기관…….","JPN":"今まで追跡してきた敵の動力機関……","ENG":"The enemy's power engine we've been tracking...","TWN":"我們之前獲得的敵機動力源……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"아베스타 드라이브를 역설계 및 소형화한 <color=#ffd34c>아스트라 드라이브</color>입니다요.","JPN":"アヴェスター・ドライブを逆設計および小型化した<color=#ffd34c>アストラ・ドライブ</color>でやんす。","ENG":"I reverse-engineered and miniaturized Avesta Drive to create this, <color=#ffd34c>Astra Drive</color>.","TWN":"阿貝斯塔引擎，我對它進行了逆向工程並製作了這個小型的<color=#ffd34c>艾斯特拉引擎</color>。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"이걸 활성화하면, 도약 능력과 공명해서 훨씬 더 빠르게 가속할 수 있을 겁니다요!","JPN":"これを活性化すると、跳躍能力と共鳴してより早く加速できるはずでやんす！","ENG":"With this enabled, you'll be able to accelerate even faster as it'll resonate with your jumping ability!","TWN":"它可以與你的跳躍能力產生共鳴，讓你加速得更快！"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"이론상으로는 단독으로 대기권에 진입해서 지구로 복귀하는 것도 가능할지 모릅니다요.","JPN":"理論上、単独で大気圏に進入して地球に帰還することもできるかもしれないでやんす。","ENG":"In theory, it could allow you to enter and exit the atmosphere entirely on your own.","TWN":"理論上，或許有可能讓你獨自進入大氣層並返回地球。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"정말이야?","JPN":"本当か？","ENG":"Really?","TWN":"真的嗎？"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"지금보다 더 빨리 달릴 수 있다고?","JPN":"今より早く走れると？","ENG":"So I can run faster now?","TWN":"能比現在跑得更快？"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"……하지만 명심하시는 겁니다요.","JPN":"……でも覚えててほしいでやんす。","ENG":"...But be careful.","TWN":"……但一定要記住這一點……！"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"아베스타 드라이브는 기본원리는 주위 침식파를 흡수하여 동력으로 환원하는 것…….","JPN":"アヴェスター・ドライブの基本原理は、周りの侵食波を吸収して動力に還元すること……","ENG":"Avesta Drive was made to absorb surrounding Corruption rays as its power source...","TWN":"阿貝斯塔引擎的基本原理是吸收周圍的侵蝕波並將其轉化為動力……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"이건 원래 침식 내성이 강한 기계에 탑재할 것을 전제로 만들어진 물건인 겁니다요.","JPN":"これは本来、侵食耐性の強い機械に搭載することを前提で作られたものでやんす。","ENG":"So it was originally designed to be mounted on machines with strong resistance to Corruption.","TWN":"最初創造它的假設是將它搭載在具有強侵蝕耐性的機器上。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"동일한 원리를 가진 아스트라 드라이브 역시 인간이 사용하기에는 다소 부적절합니다요.","JPN":"同じ原理を持つアストラ・ドライブも、人間が使うにはちょっぴり不適切でやんす。","ENG":"Astra Drive uses the same principle, and it might be unsuitable for human use.","TWN":"採用同樣原理的艾斯特拉引擎，不太適合人類使用。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"침식 내성이 강한 전대장님이라고 해도 두 번 정도가 한계인 겁니다요.","JPN":"侵食耐性の強い戦隊長だとしても、おそらく2回が限界でやんす。","ENG":"Even if your Corruption resistance is strong, one or two uses would be the limit.","TWN":"即使是耐侵蝕性強大的戰隊長，啟動第二次也已經是極限了。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"꼭 기억하시는 겁니다요! 세 번째는 없습니다요!","JPN":"絶対覚えていてほしいでやんす！　3度目はないでやんす！","ENG":"Remember that! Only use it twice!","TWN":"一定要記住！不能再啟動第三次了！"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"……알겠어.","JPN":"……わかった。","ENG":"...Okay.","TWN":"……知道了。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"명심할게, 고마워, 쥐스틴.","JPN":"覚えておくよ。ありがとう、ジュスティーヌ。","ENG":"I'll keep that in mind. Thanks, Justine.","TWN":"我會記住這一點的，謝謝你，潔絲婷。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"……흐윽.","JPN":"……ううっ。","ENG":"...*Sniffle*","TWN":"……嗚嗚。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L27_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"끄윽, 아주 분합니다요.","JPN":"くうっ、めちゃくちゃ悔しいでやんす。","ENG":"Ngh, I'm so mad.","TWN":"呃啊，我真的好難過……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"쥐스틴……?","JPN":"ジュスティーヌ……？","ENG":"Justine...?","TWN":"潔絲婷……？"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"이렇게 분한 마음은……!! 태어나서 처음인 것입니다요……!!","JPN":"こんな悔しい気持ちは……！！　生まれて初めてでやんす……！！","ENG":"I've never felt this angry...!! In my life before...!!","TWN":"這種悔恨的感覺……！！還是我人生中第一次……！！"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"제게 시간과 예산이 조금만 더 있었더라면!! 제게 재능이 조금만 더 있었더라면……!!","JPN":"あたいに時間と予算がもうちょっとあれば！！　あたいにもう少しだけ才能があれば……！！","ENG":"If I only had a bit more time and money!! If I was a bit more talented...!!","TWN":"如果我有更多的時間和預算就好了！如果我再多一點天賦就好了……！！"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"애초부터 이런 불안정하고 위험한 장비 같은 건 드리지도 않았을 겁니다요!!","JPN":"こんな不安定で危険な装備は渡さなかったはずでやんす！！","ENG":"Then I wouldn't have to give you a piece of such unstable, dangerous equipment in the first place!!","TWN":"我一開始就不會給你這麼不穩定又危險的裝備！！"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"흐윽, 그렇지만……!! 그렇지만……!!","JPN":"ううっ、でも……！！　でも……！！","ENG":"*Sniffle* But...! But...!!","TWN":"嗚嗚，但是……！！但是……！！"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"분하지만 이게 지금 저의 최선입니다요!","JPN":"悔しいけど、これが今のあたいにできるベストでやんす！","ENG":"As much as I hate to admit it, this is the best I can do for now!","TWN":"雖然很生氣，但這是我目前能給你的最好的東西了！"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"어차피 저 같은 게 잡아도 가시리라는 건 알고 있습니다요……!","JPN":"どうせあたいなんかが止めても無駄だってことはわかってるでやんす……！","ENG":"I know that I can't stop you...!","TWN":"反正我知道，就算我再勸你也沒有用……！"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"그러니까 반드시 멋지게 성공해서 돌아오시는 겁니다요! 앨리스 전대장님!!","JPN":"だから、絶対カッコよく成功して戻ってくるでやんすよ！　アリス戦隊長！！","ENG":"So come back after a successful mission! Commander Alice!!","TWN":"所以，你一定要成功完成任務，毫髮無傷地回來！艾莉絲戰隊長！！"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"부전대장님을……! 그리고 모두를 구하는 겁니다요……!!","JPN":"副戦隊長を……！　そして、みんなを助けるでやんす……！！","ENG":"Save Deputy Commander...! And everyone else too...!!","TWN":"救下副戰隊長……！和所有人……！！"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"저는 여기서 모두를 기다리고 있겠습니다요!!","JPN":"あたいはここでみんなを待ってるでやんす！！","ENG":"I'll be here waiting for all of you!!","TWN":"我會在這裡等著大家的！！"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"최고의 선물이야. 꼬맹이.","JPN":"最高のプレゼントだ、ちんちくりん。","ENG":"This is the best gift, kid.","TWN":"這已經是最好的禮物了。小鬼。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L45_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"내가 아는 공학자 중에서 가장 뛰어난 녀석이 만든 거야. 틀림없이 도움이 되겠지.","JPN":"アタシの知る工学者の中で一番の凄腕が作ったんだ。必ず役に立つさ。","ENG":"The most brilliant engineer I know made it. I'm certain that it'll come in handy.","TWN":"它是由我認識的最傑出的工程師製作的。一定會對我有所幫助。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"이 녀석의 성능은 작전을 성공시키는 걸로 증명해 보일 테니까.","JPN":"こいつの性能は、作戦を成功させることで証明してやるよ。","ENG":"I'll prove its performance by successfully completing this operation.","TWN":"看好吧，我會用成功來證明這一點的。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"지금 저는 우주센터에 나와있는데요.","JPN":"ただいま、私は宇宙センターにいます。","ENG":"I'm currently in front of the space center.","TWN":"我們現在正在太空中心。"},"stage":{"bg":"HELI_NORMAL","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"오늘 발사가 2시간 연장되었던 GAP-13호가 이제 우주로 날아오를 준비를 마쳤습니다.","JPN":"今日発射が2時間ほど延期になっていたGAP-13号が、宇宙に飛び立つ準備を終えました。","ENG":"The two-hour-delayed GAP-13 shuttle is finally ready to be launched into space.","TWN":"預計今日發射的GAP-13號，雖然發射時間推遲了兩小時，但現在已經準備好飛入太空了。"},"stage":{"bg":"HELI_NORMAL","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"지금부터 10초 카운트 다운에 들어갑니다.","JPN":"今から10秒間のカウントダウンが始まります。","ENG":"The 10-second countdown will start now.","TWN":"現在開始10秒進入倒數計時。"},"stage":{"bg":"HELI_NORMAL","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"10, 9, 8…….","JPN":"10、9、8……","ENG":"10, 9, 8...","TWN":"10、9、8……"},"stage":{"bg":"HELI_NORMAL","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"점화되었습니다!","JPN":"点火されました！","ENG":"Ignition!","TWN":"點火！"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_16"},{"id":"L9_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"GAP-13호 붉은 불꽃을 뒤로 하며, 하늘로 날아오르고 있습니다!","JPN":"GAP-13号、赤い炎を吹き出しながら空へ飛びあがっています！","ENG":"GAP-13 is soaring through the sky with red flames shooting from behind!","TWN":"GAP-13號在烈焰的推動下，騰空而起直衝雲霄！"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"GAP-13호 이륙하였습니다.","JPN":"GAP-13号、離陸しました。","ENG":"We have lift off!","TWN":"GAP-13號起飛了！"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네는 매번 같은 선택을 하는군.","JPN":"君は毎度同じ選択をするな。","ENG":"You seem to make the same choices every time.","TWN":"你每次都會做出同樣的選擇。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"다른 사람을 위해 불 속에 들어가는 걸 조금도 망설이지 않아.","JPN":"他人のために、炎の中に飛び込むことをまったく厭わない。","ENG":"You never hesitate in going into the fire to save others.","TWN":"為他人毫不猶豫地跳進火海。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네는 거창한 일에는 관심이 없다고 했지?","JPN":"君は、大層なことには興味がないと言った。","ENG":"You said that you're not interested in grandiose plans, right?","TWN":"你曾說過你對這種偉大的事情不感興趣。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 자네의 그 헌신과 희생이……. 결국, 세계를 한번 구하게 될 거라네.","JPN":"だが、君のその献身と犠牲が……世界を救うことになるだろう。","ENG":"But your dedication and sacrifice... will eventually save the world.","TWN":"但你的奉獻和犧牲……最後，終究還是會拯救世界一次的吧。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아니, 내가 반드시 그렇게 만들겠네.","JPN":"いや、私が必ずそうさせてみせよう。","ENG":"No, I'll make it so that you do.","TWN":"不，我保證它會的。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그러니까 이번에는…….","JPN":"だから、今度は……","ENG":"So this time...","TWN":"所以這一次……"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"부디, 성공하길 기원하겠네, 앨리스 브레이드우드.","JPN":"どうか、健闘を祈る。アリス・ブレイドウッド。","ENG":"I wish you success, Alice Braidwood.","TWN":"祝你成功，艾莉絲·布雷德伍德。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};